const headers = $input.first().json.headers || {};
const key = headers['x-gda-key'] || headers['X-GDA-Key'] || '';
// The Webhook node already enforces n8n Header Auth.
// This node should not hardcode a rotating secret; it only confirms the expected header is present.
if (!key) throw new Error('Unauthorized: missing x-gda-key');
return $input.all();

const rows = $input.all().map(i => i.json);
const query = ($('Webhook').first().json.body || $('Webhook').first().json).query;
return [{json: {
  query,
  results: rows.map(r => ({
    source_type: r.source_type,
    source_id: r.source_id,
    title: r.source_title,
    text: r.chunk_text,
    similarity: parseFloat(r.similarity || 0).toFixed(4),
    metadata: typeof r.metadata === 'string' ? JSON.parse(r.metadata) : r.metadata
  })),
  count: rows.length
}}];
